SELECT COUNT(island_id) AS number_of_islands, AVG(price) AS average_price
FROM islands
WHERE country = 'United States';

SELECT AVG(price) AS average_income_producing_large_acreage_price
FROM islands
WHERE income_producing = 1 AND large_acreage = 1;

SELECT island_name
FROM islands
ORDER BY acreage DESC;

SELECT island_name
FROM islands
WHERE island_id = 1;
